import{_ as t,W as r,X as o,Z as a,$ as e,a0 as n,a1 as d,D as l}from"./framework-c9619a7b.js";const g={},h=d('<h2 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h2><p>UML（统一建模语言）类图是一种用于可视化和描述系统中的对象和它们之间的关系的图表。它是一种静态结构图，用于展示系统中的类、接口、对象和它们之间的关系，以及它们的属性和方法。类图通常用于软件设计和开发，以帮助开发人员更好地理解系统的结构和组成部分，以及它们之间的交互。</p><p>在UML类图中，一个类通常表示一个对象或一组相关的对象，具有属性和方法，以及与其他类之间的关系，例如继承、实现、聚合和组合等。类图还可以包括接口、枚举类型、抽象类、泛型等元素，以及它们之间的关系。通过使用UML类图，开发人员可以更好地设计、实现和维护复杂的软件系统。</p><h2 id="教程" tabindex="-1"><a class="header-anchor" href="#教程" aria-hidden="true">#</a> 教程</h2><h3 id="实体" tabindex="-1"><a class="header-anchor" href="#实体" aria-hidden="true">#</a> 实体</h3><h4 id="类-class" tabindex="-1"><a class="header-anchor" href="#类-class" aria-hidden="true">#</a> 类(Class)</h4><ol><li>类的表示</li></ol><figure><img src="https://minio.kevin2li.top/image-bed/20230429115341.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ol start="2"><li>成员可见性(Class Visibility)</li></ol><figure><img src="https://minio.kevin2li.top/image-bed/20230429115127.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ol start="3"><li>参数方向性(Parameter Directionality)</li></ol><figure><img src="https://minio.kevin2li.top/image-bed/20230429115233.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h4 id="接口-interface" tabindex="-1"><a class="header-anchor" href="#接口-interface" aria-hidden="true">#</a> 接口(Interface)</h4><figure><img src="https://minio.kevin2li.top/image-bed/202304291241293.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h4 id="包-package" tabindex="-1"><a class="header-anchor" href="#包-package" aria-hidden="true">#</a> 包(Package)</h4><figure><img src="https://minio.kevin2li.top/image-bed/202304291242751.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="关系" tabindex="-1"><a class="header-anchor" href="#关系" aria-hidden="true">#</a> 关系</h3><figure><img src="https://minio.kevin2li.top/image-bed/20230429115420.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h4 id="继承关系-inheritance" tabindex="-1"><a class="header-anchor" href="#继承关系-inheritance" aria-hidden="true">#</a> 继承关系(Inheritance)</h4><figure><img src="https://minio.kevin2li.top/image-bed/202304291244709.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>在UML类图中，泛化关系用空心三角和实线组成的箭头表示，从子类指向父类.</p><h4 id="实现关系-aggregation" tabindex="-1"><a class="header-anchor" href="#实现关系-aggregation" aria-hidden="true">#</a> 实现关系(Aggregation)</h4><figure><img src="https://minio.kevin2li.top/image-bed/202304291249118.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>实现关系是指接口及其实现类之间的关系。在UML类图中，实现关系用空心三角和虚线组成的箭头来表示，从实现类指向接口.</p><h4 id="关联关系-association" tabindex="-1"><a class="header-anchor" href="#关联关系-association" aria-hidden="true">#</a> 关联关系(Association)</h4><p><img src="https://minio.kevin2li.top/image-bed/202304291245448.png" alt="" loading="lazy"> 在UML图中，双向关联关系用带双箭头的实线或者无箭头的实线双线表示。单向关联用一个带箭头的实线表示，箭头指向被关联的对象.</p><blockquote><p>关联关系（Association）是指对象和对象之间的连接，它使一个对象知道另一个对象的属性和方法。在Java中，关联关系的代码表现形式为一个对象含有另一个对象的引用。也就是说，如果一个对象的类代码中，包含有另一个对象的引用，那么这两个对象之间就是关联关系。</p><p>关联关系有单向关联和双向关联。如果两个对象都知道（即可以调用）对方的公共属性和操作，那么二者就是双向关联。如果只有一个对象知道（即可以调用）另一个对象的公共属性和操作，那么就是单向关联。大多数关联都是单向关联，单向关联关系更容易建立和维护，有助于寻找可重用的类。</p></blockquote><h4 id="依赖关系-dependency" tabindex="-1"><a class="header-anchor" href="#依赖关系-dependency" aria-hidden="true">#</a> 依赖关系(Dependency)</h4><p><img src="https://minio.kevin2li.top/image-bed/202304291246875.png" alt="" loading="lazy"> 在UML类图中，依赖关系用一个带虚线的箭头表示，由使用方指向被使用方，表示使用方对象持有被使用方对象的引用.</p><blockquote><p>依赖关系在Java中的具体代码表现形式为B为A的构造器或方法中的局部变量、方法或构造器的参数、方法的返回值，或者A调用B的静态方法。</p></blockquote><h4 id="聚合关系-aggregation" tabindex="-1"><a class="header-anchor" href="#聚合关系-aggregation" aria-hidden="true">#</a> 聚合关系(Aggregation)</h4><p><img src="https://minio.kevin2li.top/image-bed/202304291247951.png" alt="" loading="lazy"> 在UML图中，聚合关系用空心菱形加实线箭头表示，空心菱形在整体一方，箭头指向部分一方.</p><blockquote><p>聚合（Aggregation）是关联关系的一种特例，它体现的是整体与部分的拥有关系，即 “has a” 的关系。此时整体与部分之间是可分离的，它们可以具有各自的生命周期，部分可以属于多个整体对象，也可以为多个整体对象共享，所以聚合关系也常称为共享关系。例如，公司部门与员工的关系，一个员工可以属于多个部门，一个部门撤消了，员工可以转到其它部门。</p></blockquote><h4 id="组合关系-composition" tabindex="-1"><a class="header-anchor" href="#组合关系-composition" aria-hidden="true">#</a> 组合关系(Composition)</h4><figure><img src="https://minio.kevin2li.top/image-bed/202304291248679.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><blockquote><p>组合（Composition）也是关联关系的一种特例，它同样体现整体与部分间的包含关系，即 “contains a” 的关系。但此时整体与部分是不可分的，部分也不能给其它整体共享，作为整体的对象负责部分的对象的生命周期。这种关系比聚合更强，也称为强聚合。如果A组合B，则A需要知道B的生存周期，即可能A负责生成或者释放B，或者A通过某种途径知道B的生成和释放。</p></blockquote><h3 id="数量" tabindex="-1"><a class="header-anchor" href="#数量" aria-hidden="true">#</a> 数量</h3><figure><img src="https://minio.kevin2li.top/image-bed/202304291157763.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><h3 id="订单系统" tabindex="-1"><a class="header-anchor" href="#订单系统" aria-hidden="true">#</a> 订单系统</h3><figure><img src="https://minio.kevin2li.top/image-bed/202304291158916.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="gui系统" tabindex="-1"><a class="header-anchor" href="#gui系统" aria-hidden="true">#</a> GUI系统</h3><figure><img src="https://minio.kevin2li.top/image-bed/202304291159104.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h2>',44),c={href:"https://creately.com/blog/software-teams/class-diagram-tutorial/",target:"_blank",rel:"noopener noreferrer"},s={href:"https://www.visual-paradigm.com/guide/uml-unified-modeling-language/uml-class-diagram-tutorial/",target:"_blank",rel:"noopener noreferrer"},p={href:"https://zhuanlan.zhihu.com/p/109655171",target:"_blank",rel:"noopener noreferrer"};function f(u,m){const i=l("ExternalLinkIcon");return r(),o("div",null,[h,a("ol",null,[a("li",null,[a("a",c,[e("The Easy Guide to UML Class Diagrams | Class Diagram Tutorial"),n(i)])]),a("li",null,[a("a",s,[e("UML Class Diagram Tutorial"),n(i)])]),a("li",null,[a("a",p,[e("30分钟学会UML类图"),n(i)])])])])}const x=t(g,[["render",f],["__file","UML类图教程.html.vue"]]);export{x as default};
